request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?orig ?norm ?choreo ?elemType ?elemName WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?orig . }
  OPTIONAL { ?model tai:normalizedId ?norm . }
  FILTER(?norm = "2aa476e4bbdf451083ec316570f7a3be" || ?orig = "2aa476e4bbdf451083ec316570f7a3be")

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  {
    ?task a bboExt:ChoreographyTask .
    OPTIONAL { ?task bbo:name ?elemName . }
    BIND(bboExt:ChoreographyTask AS ?elemType)
    BIND(?task AS ?elem)
  }
  UNION
  {
    ?start a bboExt:StartEvent .
    OPTIONAL { ?start bbo:name ?elemName . }
    BIND(bboExt:StartEvent AS ?elemType)
    BIND(?start AS ?elem)
  }
  FILTER(BOUND(?elem))

  # return a mix; we'll filter client-side by name substring in results
  OPTIONAL { FILTER(?elemName != "") }
}
LIMIT 25
